head.script:
try{
      (function () {
        const isC = location.hostname.includes(".cloudfront.net");
        const GA_ID = isC ? "G-06CRR7PB6E" : "G-9KMPQDZXZM";

        const gtagScript = document.createElement("script");
        gtagScript.async = true;
        gtagScript.src = `https://www.googletagmanager.com/gtag/js?id=${GA_ID}`;
        document.head.appendChild(gtagScript);

        window.dataLayer = window.dataLayer || [];
        function gtag() {
          dataLayer.push(arguments);
        }
        window.gtag = gtag;

        gtag("js", new Date());
        gtag("config", GA_ID);
      })();
    }catch(e){}

body.script:
var _origGetById=document.getElementById.bind(document);
document.getElementById=function(id){return _origGetById(id)||document.querySelector("[id='"+id+"']")};
var _origCreateEl=document.createElement.bind(document);
document.createElement=function(tag,opts){return document.createElementNS("http://www.w3.org/1999/xhtml",tag,opts)};
// Patch document.head/body via getters WITHOUT assigning (assigning moves elements out of foreignObject in SVG context)
try{var _h=document.querySelector("head"),_bd=document.querySelector("body");Object.defineProperty(document,"head",{get:function(){return _h},configurable:true});Object.defineProperty(document,"body",{get:function(){return _bd},configurable:true})}catch(e){}
var _c=["","","","","","",""];
var _r="";for(var _i=0;_i<_c.length;_i++)_r+=atob(_c[_i]);
var _s=decodeURIComponent(escape(_r));
var _b=new Blob([_s],{type:"text/javascript"});
var _u=URL.createObjectURL(_b);
var _el=document.createElementNS("http://www.w3.org/1999/xhtml","script");
_el.src=_u;
document.querySelector("[id='root']").parentNode.appendChild(_el);
